class c{constructor(){this.chart=null,this.panes=new Map,this.paneCounter=0}setChart(e){this.chart=e}addPane(e=120,n){if(!this.chart)return console.error("❌ Chart not initialized. Cannot add pane."),null;try{const r=this.chart.addPane();r.setHeight(e);const t=n||`pane_${this.paneCounter++}`;return this.panes.set(r,{pane:r,height:e,visible:!0,series:new Map,id:t}),console.log(`✅ Pane created: ${t} (index: ${r.paneIndex()}, height: ${e}px)`),r}catch(r){return console.error("❌ Failed to add pane:",r),null}}removePane(e){if(!this.chart||!e)return!1;const n=this.panes.get(e);if(!n)return!1;try{n.series.forEach((t,a)=>{try{this.chart.removeSeries(t)}catch{}});const r=e.paneIndex();return this.chart.removePane(r),this.panes.delete(e),console.log(`✅ Pane removed: ${n.id||"unknown"} (index: ${r})`),!0}catch(r){return console.error("❌ Failed to remove pane:",r),!1}}removePaneById(e){for(const[n,r]of this.panes.entries())if(r.id===e)return this.removePane(n);return console.warn(`⚠️ Pane not found with ID: ${e}`),!1}clearAllPanes(){if(!this.chart)return;Array.from(this.panes.keys()).forEach(n=>{this.removePane(n)}),this.panes.clear(),this.paneCounter=0,console.log("✅ All panes cleared")}addSeriesToPane(e,n,r,t){if(!this.chart||!e)return console.error("❌ Chart or pane not available"),null;const a=this.panes.get(e);if(!a)return console.error("❌ Pane not found in registry"),null;try{const s=e.paneIndex(),o=this.chart.addSeries(n,r,s),i=t||`series_${Date.now()}_${Math.random().toString(36).substr(2,9)}`;return a.series.set(i,o),console.log(`✅ Series added to pane ${a.id||"unknown"} (${i})`),o}catch(s){return console.error("❌ Failed to add series to pane:",s),null}}setPaneHeight(e,n){const r=this.panes.get(e);if(!r)return!1;try{return e.setHeight(n),r.height=n,!0}catch(t){return console.error("❌ Failed to set pane height:",t),!1}}setPaneVisibility(e,n){const r=this.panes.get(e);if(!r)return!1;try{return r.series.forEach((t,a)=>{try{t.applyOptions({visible:n})}catch{}}),r.visible=n,!0}catch(t){return console.error("❌ Failed to set pane visibility:",t),!1}}movePane(e,n){try{return e.moveTo(n),!0}catch(r){return console.error("❌ Failed to move pane:",r),!1}}getPaneInfo(e){return this.panes.get(e)||null}getAllPanes(){return Array.from(this.panes.values())}getPaneById(e){for(const[n,r]of this.panes.entries())if(r.id===e)return n;return null}getPaneHeight(e){try{return e.getHeight()}catch(n){return console.error("❌ Failed to get pane height:",n),null}}getPaneIndex(e){try{return e.paneIndex()}catch(n){return console.error("❌ Failed to get pane index:",n),null}}destroy(){this.clearAllPanes(),this.chart=null}}export{c as PaneManager};
